script:
frappe.ui.form.on("Hostel Attendance", {

    refresh(frm) {

        // Default Attendance Status
        if (frm.is_new() && !frm.doc.attendance_status) {
            frm.set_value("attendance_status", "Present");
        }

    },

    student(frm) {

        if (!frm.doc.student) {
            return;
        }

        // Fetch Student Name
        frappe.db.get_value(
            "Student",
            frm.doc.student,
            "student_name",
            (r) => {
                if (r) {
                    frm.set_value("student_name", r.student_name);
                }
            }
        );

        // Fetch Active Hostel Admission
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Hostel Admission",
                filters: {
                    student: frm.doc.student,
                    admission_status: "Active"
                },
                fields: [
                    "name",
                    "hostel",
                    "hostel_block",
                    "hostel_room"
                ],
                limit_page_length: 1
            },
            callback: function(r) {

                if (r.message && r.message.length > 0) {

                    let d = r.message[0];

                    frm.set_value("hostel_admission", d.name);
                    frm.set_value("hostel", d.hostel);
                    frm.set_value("hostel_block", d.hostel_block);
                    frm.set_value("hostel_room", d.hostel_room);

                } else {

                    frappe.msgprint(__("This student does not have an Active Hostel Admission."));

                }

            }
        });

    }

});
